sources.expression:
$wpdb->get_col(
			$wpdb->prepare(
				"SELECT user_id FROM {$wpdb->prefix}" . self::AUTH_TABLE_NAME . " WHERE user_id IN ($placeholders_pre)",
				$all_user_ids
			)
		)

$wpdb->get_results(
			$wpdb->prepare(
				"SELECT option_name, option_value AS timeout_value
				FROM {$wpdb->options}
				WHERE option_name LIKE %s
				AND option_value <= %d",
				$wpdb->esc_like( '_transient_timeout_2fa_setup_secret_' ) . '%',
				time() + self::SETUP_SECRET_TIMEOUT
			)
		)

$wpdb->get_results(
				$wpdb->prepare(
					"SELECT post_content
					FROM {$wpdb->posts}
					WHERE post_type = %s
					AND post_status = %s",
					'acf-post-type',
					'publish'
				)
			)

